  create policy "all"
  on "public"."notifications"
  as permissive
  for all
  to public
using (true)
with check (true);


CREATE TRIGGER handle_friend_request_notifications AFTER INSERT ON public.friend_requests FOR EACH ROW EXECUTE FUNCTION public.create_friend_request_notifications();

CREATE TRIGGER handle_message_notifications AFTER INSERT ON public.messages FOR EACH ROW EXECUTE FUNCTION public.create_message_notifications();

CREATE TRIGGER handle_notifications_broadcast AFTER INSERT OR UPDATE ON public.notifications FOR EACH ROW EXECUTE FUNCTION public.notifications_broadcast();

CREATE TRIGGER handle_room_user_message_notifications_read AFTER UPDATE ON public.room_user FOR EACH ROW EXECUTE FUNCTION public.mark_message_notifications_as_read();


  create policy "users can receive own notification broadcasts"
  on "realtime"."messages"
  as permissive
  for select
  to authenticated
using (((extension = 'broadcast'::text) AND (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.user_id = auth.uid()) AND (('notification:'::text || (p.id)::text) = realtime.topic()))))));



